def analyse_cohort_assessment_performance(
    cohort_name: str,
    assessment_results: list[dict],
    pass_threshold: int = 80,
) -> dict:
    """Analyse assessment results for a training cohort to identify knowledge gaps."""
    scores = [r["score"] for r in assessment_results]
    pass_count = sum(1 for s in scores if s >= pass_threshold)

    # Aggregate question-level performance
    question_performance = {}
    for result in assessment_results:
        for q_id, correct in result.get("question_responses", {}).items():
            if q_id not in question_performance:
                question_performance[q_id] = {"correct": 0, "total": 0}
            question_performance[q_id]["total"] += 1
            if correct:
                question_performance[q_id]["correct"] += 1

    # Find low-performing questions (< 60% correct)
    weak_questions = {
        q_id: round(data["correct"] / data["total"] * 100, 1)
        for q_id, data in question_performance.items()
        if data["correct"] / data["total"] < 0.60
    }

    return {
        "cohort": cohort_name,
        "n_learners": len(assessment_results),
        "mean_score": round(sum(scores) / len(scores), 1),
        "pass_rate_pct": round(pass_count / len(assessment_results) * 100, 1),
        "score_distribution": {
            "90-100": sum(1 for s in scores if s >= 90),
            "80-89": sum(1 for s in scores if 80 <= s < 90),
            "70-79": sum(1 for s in scores if 70 <= s < 80),
            "below_70": sum(1 for s in scores if s < 70),
        },
        "weak_questions": weak_questions,
        "action_required": len(weak_questions) > 0 or pass_count / len(assessment_results) < 0.75,
    }


results = analyse_cohort_assessment_performance(
    cohort_name="Wave 1 — APAC Support Agents",
    assessment_results=[
        {"score": 87, "question_responses": {"q1": True, "q2": True, "q3": False, "q4": True}},
        {"score": 73, "question_responses": {"q1": True, "q2": False, "q3": False, "q4": True}},
        {"score": 93, "question_responses": {"q1": True, "q2": True, "q3": True, "q4": True}},
        {"score": 60, "question_responses": {"q1": False, "q2": False, "q3": False, "q4": True}},
    ],
)
print(f"Cohort: {results['cohort']} ({results['n_learners']} learners)")
print(f"Mean score: {results['mean_score']}% | Pass rate: {results['pass_rate_pct']}%")
if results['weak_questions']:
    print(f"Weak questions (< 60% correct): {list(results['weak_questions'].keys())}")
